const [sortConfig, setSortConfig] = useState({ column: null, direction: 'asc' });

const handleSort = (column) => {
  const direction = sortConfig.column === column && sortConfig.direction === 'asc' ? 'desc' : 'asc';
  setSortConfig({ column, direction });
};

const sortedData = useMemo(() => {
  if (!sortConfig.column) return data;
  return [...data].sort((a, b) => {
    if (a[sortConfig.column] < b[sortConfig.column]) return sortConfig.direction === 'asc' ? -1 : 1;
    if (a[sortConfig.column] > b[sortConfig.column]) return sortConfig.direction === 'asc' ? 1 : -1;
    return 0;
  });
}, [data, sortConfig]);

// In JSX:
<th className="fd-table__cell fd-table__cell--header-sortable"
    onClick={() => handleSort('name')}
    aria-sort={sortConfig.column === 'name' ? (sortConfig.direction === 'asc' ? 'ascending' : 'descending') : 'none'}>
  Name
