const openBtn = document.querySelector('#open-dialog');
const dialog = document.querySelector('.fd-dialog');
const closeBtn = dialog.querySelector('.fd-dialog__close');
const cancelBtn = dialog.querySelector('[data-action="cancel"]');

openBtn.addEventListener('click', () => {
  dialog.classList.add('fd-dialog--active');
  dialog.setAttribute('aria-hidden', 'false');

  // Focus first focusable element
  const firstFocusable = dialog.querySelector('button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])');
  firstFocusable?.focus();

  // Trap focus
  document.addEventListener('keydown', trapFocus);
});

const closeDialog = () => {
  dialog.classList.remove('fd-dialog--active');
  dialog.setAttribute('aria-hidden', 'true');
  openBtn.focus(); // Return focus
  document.removeEventListener('keydown', trapFocus);
};

closeBtn.addEventListener('click', closeDialog);
cancelBtn.addEventListener('click', closeDialog);

// Close on Escape
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape' && dialog.classList.contains('fd-dialog--active')) {
    closeDialog();
  }
});

