const [isOpen, setIsOpen] = useState(false);
const dialogRef = useRef(null);
const openButtonRef = useRef(null);

const openDialog = () => {
  setIsOpen(true);
};

const closeDialog = () => {
  setIsOpen(false);
  openButtonRef.current?.focus();
};

