const input = document.querySelector('#email');
const errorMsg = document.querySelector('#email-error');

const validateEmail = (email) => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
};

input.addEventListener('input', (e) => {
  const value = e.target.value;
  if (value && !validateEmail(value)) {
    input.classList.add('is-error');
    input.setAttribute('aria-invalid', 'true');
    errorMsg.textContent = 'Please enter a valid email address';
    errorMsg.classList.remove('fd-form-message--success');
    errorMsg.classList.add('fd-form-message--error');
  } else if (value) {
    input.classList.remove('is-error');
    input.classList.add('is-success');
    input.setAttribute('aria-invalid', 'false');
    errorMsg.textContent = 'Email is valid';
    errorMsg.classList.remove('fd-form-message--error');
    errorMsg.classList.add('fd-form-message--success');
  } else {
    input.classList.remove('is-error', 'is-success');
    input.removeAttribute('aria-invalid');
    errorMsg.textContent = '';
  }
});

