const triggerBtn = document.querySelector('[data-popover-trigger]');
const popover = document.querySelector('.fd-popover__popper');

triggerBtn.addEventListener('click', () => {
  const isHidden = popover.getAttribute('aria-hidden') === 'true';
  popover.setAttribute('aria-hidden', !isHidden);
  triggerBtn.setAttribute('aria-expanded', isHidden);

  if (isHidden) {
    popover.style.display = 'block';
  } else {
    popover.style.display = 'none';
  }
});

// Close on click outside
document.addEventListener('click', (e) => {
  if (!triggerBtn.contains(e.target) && !popover.contains(e.target)) {
    popover.setAttribute('aria-hidden', 'true');
    triggerBtn.setAttribute('aria-expanded', 'false');
    popover.style.display = 'none';
  }
});

