const [activeTab, setActiveTab] = useState(0);

const handleKeyDown = (e, currentIndex) => {
  if (e.key === 'ArrowRight') {
    setActiveTab((currentIndex + 1) % tabs.length);
  } else if (e.key === 'ArrowLeft') {
    setActiveTab((currentIndex - 1 + tabs.length) % tabs.length);
  } else if (e.key === 'Home') {
    setActiveTab(0);
  } else if (e.key === 'End') {
    setActiveTab(tabs.length - 1);
  }
};

// In JSX:
<ul role="tablist" className="fd-tabs">
  {tabs.map((tab, index) => (
    <li key={index} role="presentation">
      <a role="tab"
         className={activeTab === index ? 'is-selected' : ''}
         aria-selected={activeTab === index}
         tabIndex={activeTab === index ? 0 : -1}
         onClick={() => setActiveTab(index)}
         onKeyDown={(e) => handleKeyDown(e, index)}>
        {tab.label}
      </a>
    </li>
  ))}
